  const clusters = await router.fetchMatchedMarketClusters({
    query: "Satoshi",
    relation: "identity",
    minVenues: 2,
    includeRawMatches: true,
    limit: 5,
  });

  for (const cluster of clusters) {
    console.log(
      cluster.canonicalTitle,
      cluster.markets.map((market) => market.sourceExchange),
    );
  }
}

main();
